-- AUTO-GENERIERT aus app/assets/catalog.json — nicht von Hand bearbeiten.
-- Neu erzeugen: node supabase/seed/generate_seed.mjs
-- Idempotent: upsert je Schlüssel.

on conflict (key) do update set
  defino_level = excluded.defino_level,
  defino_field = excluded.defino_field,
  name_de = excluded.name_de,
  name_en = excluded.name_en,
  icon = excluded.icon,
  sort_order = excluded.sort_order,
  purpose_de = excluded.purpose_de,
  purpose_en = excluded.purpose_en,
  relevance_de = excluded.relevance_de,
  relevance_en = excluded.relevance_en,
  watch_de = excluded.watch_de,
  watch_en = excluded.watch_en,
  active = excluded.active
;

delete from public.contract_fields where category_key in ('privathaftpflicht', 'berufsunfaehigkeit', 'krankenversicherung', 'krankentagegeld', 'pflegeversicherung', 'risikolebensversicherung', 'unfallversicherung', 'hausratversicherung', 'wohngebaeudeversicherung', 'rechtsschutzversicherung', 'kfzversicherung', 'tierhalterhaftpflicht', 'liquiditaetsreserve', 'altersvorsorge', 'lebensversicherung', 'immobilienfinanzierung', 'bausparvertrag', 'depot', 'sparplan', 'tagesgeld_festgeld', 'sterbegeldversicherung', 'reiseversicherung');

;

on conflict (slug) do update set
  category_de = excluded.category_de,
  category_en = excluded.category_en,
  title_de = excluded.title_de,
  title_en = excluded.title_en,
  body_de = excluded.body_de,
  body_en = excluded.body_en,
  contract_key = excluded.contract_key,
  sort_order = excluded.sort_order,
  active = excluded.active
;

-- contracts.contract_type an den Katalog binden (idempotent neu anlegen).
alter table public.contracts drop constraint if exists contracts_contract_type_fkey;
alter table public.contracts add constraint contracts_contract_type_fkey
  foreign key (contract_type) references public.contract_categories (key) on update cascade;
