insert into public.contract_categories
  (key, defino_level, defino_field, name_de, name_en, icon, sort_order, purpose_de, purpose_en, relevance_de, relevance_en, watch_de, watch_en, active)
values
  ('privathaftpflicht', 1, 'Existenzielle Risiken', 'Privathaftpflicht', 'Personal liability', 'shield', 10, 'Übernimmt Schäden, die du als Privatperson anderen zufügst — Personen-, Sach- und daraus folgende Vermögensschäden.', 'Covers damage you cause to others as a private individual — personal injury, property damage and resulting financial loss.', 'Eine anerkannte Bedarfssystematik ordnet die private Haftpflicht der Stufe 1 (Grundbedarf) zu — sie zählt zu den existenziell bedeutenden Risiken, weil Schadenersatzforderungen unbegrenzt hoch sein können.', 'A recognised needs hierarchy places personal liability in level 1 (basic needs) — it counts among the existentially relevant risks because liability claims can be unlimited in size.', 'Höhe der Deckungssumme, ob alle Haushaltsmitglieder mitversichert sind, und ob mehrere Verträge denselben Schutz doppelt abdecken.', 'The coverage amount, whether all household members are included, and whether several policies cover the same risk twice.', true),
  ('berufsunfaehigkeit', 1, 'Absicherung der Arbeitskraft', 'Berufsunfähigkeit', 'Disability insurance', 'briefcase', 20, 'Zahlt eine vereinbarte monatliche Rente, wenn du deinen zuletzt ausgeübten Beruf aus gesundheitlichen Gründen voraussichtlich dauerhaft nicht mehr ausüben kannst.', 'Pays an agreed monthly pension if you can probably no longer work in your most recent occupation for health reasons on a lasting basis.', 'Eine anerkannte Bedarfssystematik behandelt die Absicherung der Arbeitskraft als Stufe-1-Thema, da das Erwerbseinkommen für die meisten Haushalte die wichtigste Einnahmequelle ist.', 'A recognised needs hierarchy treats protecting your earning ability as a level 1 topic, since employment income is the most important source of income for most households.', 'Höhe und Laufzeit der Rente, der genaue BU-Begriff im Vertrag, Nachversicherungs- und Dynamikoptionen sowie Ausschlüsse.', 'The amount and term of the pension, the exact definition of disability in the contract, top-up and dynamic options, and exclusions.', true),
  ('krankenversicherung', 1, 'Krankheit', 'Krankenversicherung', 'Health insurance', 'health', 30, 'Trägt Kosten für medizinische Behandlung. Als Voll- oder als Zusatzversicherung (z. B. Zahn, stationär) möglich.', 'Covers the cost of medical treatment. Available as full cover or as supplementary cover (e.g. dental, inpatient).', 'Der Krankenversicherungsschutz gehört nach anerkannter Bedarfssystematik zur Stufe 1; in Deutschland besteht zudem eine gesetzliche Versicherungspflicht.', 'Health cover belongs to level 1 under a recognised needs hierarchy; in Germany there is also a statutory obligation to be insured.', 'Art des Tarifs, Erstattungssätze, jährliche Höchstgrenzen und Wartezeiten — und ob Zusatzbausteine mit der Hauptversicherung überlappen.', 'The type of tariff, reimbursement rates, annual limits and waiting periods — and whether add-ons overlap with the main policy.', true),
  ('krankentagegeld', 1, 'Absicherung der Arbeitskraft', 'Krankentagegeld', 'Sick-pay insurance', 'income', 35, 'Ersetzt Einkommen bei längerer Arbeitsunfähigkeit, wenn die Lohnfortzahlung endet — als vereinbarter Tagessatz.', 'Replaces income during longer periods of incapacity to work once continued pay ends — as an agreed daily amount.', 'Als Baustein der Arbeitskraftabsicherung ordnet eine anerkannte Bedarfssystematik dieses Thema der Stufe 1 zu, besonders relevant für Selbstständige und Gutverdiener.', 'As part of protecting your earning ability, a recognised needs hierarchy assigns this topic to level 1, especially relevant for the self-employed and higher earners.', 'Höhe des Tagegelds, ab welchem Tag es gezahlt wird (Karenzzeit) und wie es zur Lohnfortzahlung passt.', 'The daily amount, from which day it is paid (waiting period) and how it fits with continued pay.', true),
  ('pflegeversicherung', 1, 'Pflegebedürftigkeit', 'Pflegeversicherung', 'Long-term care insurance', 'elderly', 40, 'Deckt Kosten bei Pflegebedürftigkeit ab. Die gesetzliche Pflegeversicherung leistet nur einen Teil; private Zusatztarife ergänzen sie.', 'Covers the cost of long-term care. Statutory care insurance pays only part of it; private supplements top it up.', 'Eine anerkannte Bedarfssystematik führt das Pflegerisiko als existenzielles Thema der Stufe 1, da die Versorgungslücke im Pflegefall erheblich sein kann.', 'A recognised needs hierarchy lists the care risk as an existential level 1 topic, because the funding gap in a care situation can be substantial.', 'Art der Leistung (Tagegeld, Kostenerstattung oder Rente), Höhe je Pflegegrad und ob die Leistung dynamisch steigt.', 'The type of benefit (daily allowance, cost reimbursement or pension), the amount per care level and whether it rises dynamically.', true),
  ('risikolebensversicherung', 1, 'Hinterbliebenenabsicherung', 'Risikolebensversicherung', 'Term life insurance', 'umbrella', 50, 'Zahlt im Todesfall der versicherten Person eine vereinbarte Summe an die Bezugsberechtigten — reiner Risikoschutz ohne Sparanteil.', 'Pays an agreed sum to the beneficiaries if the insured person dies — pure protection with no savings component.', 'Die Absicherung Hinterbliebener ist nach anerkannter Bedarfssystematik ein Stufe-1-Thema, vor allem bei Familien mit Kindern oder gemeinsamen Krediten.', 'Protecting surviving dependants is a level 1 topic under a recognised needs hierarchy, above all for families with children or shared loans.', 'Höhe der Versicherungssumme im Verhältnis zum Bedarf, Laufzeit und die korrekte Bezugsberechtigung.', 'The sum insured relative to the need, the term and the correct beneficiary designation.', true),
  ('unfallversicherung', 1, 'Invalidität durch Unfall', 'Unfallversicherung', 'Accident insurance', 'healing', 60, 'Leistet bei bleibenden Schäden infolge eines Unfalls, meist als Einmalkapital abhängig vom Invaliditätsgrad.', 'Pays out for lasting damage following an accident, usually as a lump sum depending on the degree of disability.', 'Eine anerkannte Bedarfssystematik betrachtet unfallbedingte Invalidität im Rahmen der Grundabsicherung; sie ergänzt, ersetzt aber keine Berufsunfähigkeitsabsicherung.', 'A recognised needs hierarchy considers accident-related disability within basic protection; it complements but does not replace disability cover.', 'Höhe der Invaliditätssumme, vereinbarte Progression und welche Ereignisse als Unfall gelten.', 'The disability sum, the agreed progression and which events count as an accident.', true),
  ('hausratversicherung', 1, 'Sachwerte des Haushalts', 'Hausratversicherung', 'Household contents insurance', 'sofa', 70, 'Ersetzt Hausrat (Möbel, Kleidung, Elektronik) bei Schäden durch Feuer, Leitungswasser, Sturm oder Einbruchdiebstahl.', 'Replaces household contents (furniture, clothing, electronics) for damage from fire, water, storm or burglary.', 'Eine anerkannte Bedarfssystematik zählt den Schutz wesentlicher Sachwerte zum Grundbedarf, da ein Totalverlust kurzfristig hohe Wiederbeschaffungskosten verursacht.', 'A recognised needs hierarchy counts protecting essential possessions as a basic need, since a total loss causes high replacement costs at short notice.', 'Versicherungssumme im Verhältnis zur Wohnfläche (Unterversicherung vermeiden) und ob Elementarschäden eingeschlossen sind.', 'The sum insured relative to the living space (avoid underinsurance) and whether natural-hazard damage is included.', true),
  ('wohngebaeudeversicherung', 1, 'Wohneigentum', 'Wohngebäudeversicherung', 'Residential building insurance', 'house', 80, 'Schützt das Gebäude selbst (Mauerwerk, Dach, fest Verbautes) vor Schäden durch Feuer, Leitungswasser, Sturm und Hagel.', 'Protects the building itself (structure, roof, fixtures) against fire, water, storm and hail damage.', 'Für Wohneigentümer ist dieser Schutz nach anerkannter Bedarfssystematik Teil der Grundabsicherung, da ein Gebäudeschaden die Existenz gefährden kann.', 'For homeowners this cover is part of basic protection under a recognised needs hierarchy, since building damage can threaten one''s livelihood.', 'Ob Elementarschäden (Überschwemmung, Erdbeben) eingeschlossen sind und ob die Versicherungssumme zum Wiederaufbauwert passt.', 'Whether natural-hazard damage (flood, earthquake) is included and whether the sum insured matches the rebuild value.', true),
  ('rechtsschutzversicherung', 1, 'Rechtliche Auseinandersetzungen', 'Rechtsschutzversicherung', 'Legal expenses insurance', 'gavel', 90, 'Übernimmt Kosten rechtlicher Auseinandersetzungen (Anwalt, Gericht, Gutachten) in den vereinbarten Lebensbereichen.', 'Covers the cost of legal disputes (lawyer, court, expert opinions) in the agreed areas of life.', 'Eine anerkannte Bedarfssystematik ordnet den Rechtsschutz dem Grundbedarf zu, weil Prozesskosten im Streitfall erheblich und schwer planbar sind.', 'A recognised needs hierarchy assigns legal expenses to basic needs, because litigation costs are substantial and hard to plan for.', 'Welche Bereiche eingeschlossen sind (privat, beruflich, Verkehr, Wohnen), Wartezeiten und Selbstbeteiligung.', 'Which areas are included (private, work, traffic, housing), waiting periods and the deductible.', true),
  ('kfzversicherung', 1, 'Kraftfahrzeug', 'Kfz-Versicherung', 'Motor insurance', 'car', 100, 'Deckt Schäden rund um das Fahrzeug ab. Die Haftpflicht ist gesetzlich vorgeschrieben; Teil- und Vollkasko sind freiwillig.', 'Covers vehicle-related damage. Third-party liability is mandatory; partial and full comprehensive cover are optional.', 'Die Kfz-Haftpflicht ist gesetzlich verpflichtend; eine anerkannte Bedarfssystematik betrachtet das Halten eines Fahrzeugs als individuelle Bedarfsfrage.', 'Motor third-party liability is mandatory by law; a recognised needs hierarchy treats running a vehicle as an individual question of need.', 'Umfang (Haftpflicht/Teil-/Vollkasko), Schadenfreiheitsklasse, Selbstbeteiligung und eingeschlossene Zusatzleistungen.', 'The scope (liability/partial/full), no-claims class, deductible and included extras.', true),
  ('tierhalterhaftpflicht', 1, 'Existenzielle Risiken', 'Tierhalterhaftpflicht', 'Animal owner liability', 'paw', 110, 'Übernimmt Schäden, die von deinem Tier (z. B. Hund oder Pferd) verursacht werden — diese sind über die Privathaftpflicht meist nicht gedeckt.', 'Covers damage caused by your animal (e.g. dog or horse) — usually not included in personal liability.', 'Als Haftungsrisiko fällt dies unter die Stufe-1-Logik einer anerkannten Bedarfssystematik; für Hunde und Pferde besteht je nach Bundesland teils eine Pflicht.', 'As a liability risk this falls under the level 1 logic of a recognised needs hierarchy; for dogs and horses it is partly mandatory depending on the federal state.', 'Deckungssumme und ob die jeweilige Tierart bzw. Nutzung (z. B. Fremdreiter) eingeschlossen ist.', 'The coverage amount and whether the specific animal or use (e.g. third-party riders) is included.', true),
  ('liquiditaetsreserve', 1, 'Liquiditätsreserve', 'Liquiditätsreserve', 'Liquidity reserve', 'wallet', 120, 'Schnell verfügbares Geld für unerwartete Ausgaben — auf Giro-, Tagesgeld- oder Sparkonto.', 'Readily available money for unexpected expenses — in a current, instant-access or savings account.', 'Eine anerkannte Bedarfssystematik stellt eine Notfallreserve an den Anfang der Grundabsicherung, bevor langfristig gespart oder investiert wird.', 'A recognised needs hierarchy places an emergency reserve at the start of basic protection, before any long-term saving or investing.', 'Ob die Reserve jederzeit verfügbar ist und in einem sinnvollen Verhältnis zu den monatlichen Fixkosten steht.', 'Whether the reserve is available at any time and reasonable relative to monthly fixed costs.', true),
  ('altersvorsorge', 2, 'Alterseinkommen', 'Altersvorsorge', 'Retirement provision', 'savings', 200, 'Baut Einkommen für den Ruhestand auf — gesetzlich, betrieblich oder privat (z. B. Riester, Rürup, private Rente).', 'Builds income for retirement — statutory, occupational or private (e.g. Riester, Rürup, private pension).', 'Die Sicherung des Lebensstandards im Alter ordnet eine anerkannte Bedarfssystematik der Stufe 2 zu — nach der Grundabsicherung, aber vor reinem Vermögensaufbau.', 'Maintaining your standard of living in old age is placed in level 2 by a recognised needs hierarchy — after basic protection but before pure wealth building.', 'Unterschied zwischen garantierten und prognostizierten Beträgen, Kosten des Vertrags und steuerliche Behandlung.', 'The difference between guaranteed and projected amounts, the contract costs and the tax treatment.', true),
  ('lebensversicherung', 2, 'Kapitalbildende Vorsorge', 'Lebensversicherung', 'Life insurance', 'family', 210, 'Verbindet Todesfallschutz mit einem Sparanteil (Kapital- oder fondsgebunden) oder dient als reiner Risikoschutz.', 'Combines death cover with a savings component (endowment or unit-linked) or serves as pure protection.', 'Kapitalbildende Lebensversicherungen wirken auf Lebensstandard und Vorsorge zugleich; eine anerkannte Bedarfssystematik betrachtet sie im Kontext der Stufe 2.', 'Capital-forming life policies affect both living standard and provision; a recognised needs hierarchy considers them in the level 2 context.', 'Art des Vertrags, Garantien, laufende Kosten und der aktuelle Rückkaufswert.', 'The type of contract, guarantees, ongoing costs and the current surrender value.', true),
  ('immobilienfinanzierung', 2, 'Immobilienfinanzierung', 'Immobilienfinanzierung', 'Mortgage / property loan', 'apartment', 220, 'Darlehen zur Finanzierung von Wohneigentum, meist mit fester Zinsbindung und regelmäßiger Tilgung.', 'A loan to finance home ownership, usually with a fixed interest period and regular repayment.', 'Laufende Finanzierungen prägen den Lebensstandard und die Liquidität; eine anerkannte Bedarfssystematik berücksichtigt Verbindlichkeiten in der Gesamtbetrachtung der Stufe 2.', 'Ongoing financing shapes living standard and liquidity; a recognised needs hierarchy includes liabilities in the level 2 overall picture.', 'Zinssatz und Ende der Zinsbindung, Höhe der Restschuld und ob Anschlussfinanzierung oder Sondertilgung möglich sind.', 'The interest rate and end of the fixed period, the remaining debt and whether refinancing or extra repayments are possible.', true),
  ('bausparvertrag', 2, 'Wohneigentum / Sparen', 'Bausparvertrag', 'Building savings contract', 'foundation', 230, 'Kombiniert eine Sparphase mit dem Anspruch auf ein zinsgünstiges Bauspardarlehen für wohnwirtschaftliche Zwecke.', 'Combines a savings phase with the right to a low-interest building loan for housing purposes.', 'Als zweckgebundenes Spar- und Finanzierungsinstrument berührt der Bausparvertrag Vorsorge und Lebensstandard (Stufe 2).', 'As an earmarked saving and financing instrument, a building savings contract touches provision and living standard (level 2).', 'Bausparsumme, aktueller Sparstand, Guthaben- und Darlehenszins sowie der Zeitpunkt der Zuteilung.', 'The contract sum, current savings balance, credit and loan interest, and the allocation date.', true),
  ('depot', 3, 'Vermögensaufbau', 'Wertpapierdepot', 'Securities portfolio', 'chart', 300, 'Verwahrt Wertpapiere wie Aktien, ETFs und Fonds zum langfristigen Vermögensaufbau.', 'Holds securities such as shares, ETFs and funds for long-term wealth building.', 'Vermögensaufbau ordnet eine anerkannte Bedarfssystematik der Stufe 3 zu — sinnvoll, wenn Grundabsicherung und Vorsorge bereits stehen.', 'A recognised needs hierarchy places wealth building in level 3 — sensible once basic protection and provision are in place.', 'Laufende Fondskosten (TER), Streuung der Positionen und das Verhältnis von Risiko zum Anlagehorizont.', 'Ongoing fund costs (TER), diversification of positions and the balance of risk and investment horizon.', true),
  ('sparplan', 3, 'Vermögensaufbau', 'Sparplan', 'Savings plan', 'trending', 310, 'Regelmäßige Einzahlung in Fonds, ETFs oder Banksparpläne zum schrittweisen Vermögensaufbau.', 'Regular contributions into funds, ETFs or bank savings plans to build wealth step by step.', 'Als Instrument des Vermögensaufbaus zählt der Sparplan zur Stufe 3 einer anerkannten Bedarfssystematik.', 'As a wealth-building instrument, a savings plan belongs to level 3 of a recognised needs hierarchy.', 'Höhe der Rate, Kosten des bespartem Produkts und Flexibilität bei Pausen oder Änderungen.', 'The contribution amount, the cost of the invested product and flexibility to pause or change.', true),
  ('tagesgeld_festgeld', 3, 'Geldanlage', 'Tagesgeld / Festgeld', 'Savings / fixed deposit', 'bank', 320, 'Verzinste Geldanlage mit hoher Sicherheit — Tagesgeld täglich verfügbar, Festgeld über eine feste Laufzeit gebunden.', 'Interest-bearing savings with high security — instant access for savings, a fixed term for fixed deposits.', 'Über die Notfallreserve hinaus angelegtes Guthaben zählt zum Vermögensaufbau (Stufe 3).', 'Balances held beyond the emergency reserve count as wealth building (level 3).', 'Zinssatz, Laufzeit und ob das Guthaben über die Einlagensicherung abgedeckt ist.', 'The interest rate, the term and whether the balance is covered by deposit protection.', true),
  ('sterbegeldversicherung', 3, 'Bestattungskosten', 'Sterbegeldversicherung', 'Funeral expenses insurance', 'candle', 330, 'Zahlt im Todesfall eine festgelegte Summe, die zur Deckung von Bestattungskosten gedacht ist.', 'Pays a set sum on death, intended to cover funeral costs.', 'Ein eng umrissener Vorsorgebaustein; eine anerkannte Bedarfssystematik betrachtet ihn nachrangig zur existenziellen Grundabsicherung.', 'A narrowly defined provision element; a recognised needs hierarchy treats it as secondary to existential basic protection.', 'Höhe der Summe im Verhältnis zu den eingezahlten Beiträgen und etwaige Wartezeiten.', 'The sum relative to the premiums paid and any waiting periods.', true),
  ('reiseversicherung', 3, 'Reise', 'Reiseversicherung', 'Travel insurance', 'flight', 340, 'Deckt reisebezogene Risiken wie Krankheit im Ausland, Reiserücktritt oder Gepäckschäden.', 'Covers travel-related risks such as illness abroad, trip cancellation or baggage loss.', 'Ein komfortorientierter Baustein; eine anerkannte Bedarfssystematik ordnet solche Risiken dem oberen Bereich (Stufe 3) zu.', 'A comfort-oriented element; a recognised needs hierarchy places such risks in the upper range (level 3).', 'Welche Bausteine enthalten sind, Geltungsbereich (Europa/weltweit) und ob es sich um Einmal- oder Jahresschutz handelt.', 'Which modules are included, the area of validity (Europe/worldwide) and whether it is single-trip or annual cover.', true)
