insert into public.knowledge_articles
  (slug, category_de, category_en, title_de, title_en, body_de, body_en, contract_key, sort_order, active)
values
  ('bu', 'Vorsorge', 'Provision', 'Wie funktioniert eine Berufsunfähigkeitsversicherung?', 'How does disability insurance work?', '["Eine Berufsunfähigkeitsversicherung (BU) zahlt eine vereinbarte monatliche Rente, wenn du deinen zuletzt ausgeübten Beruf aus gesundheitlichen Gründen voraussichtlich dauerhaft nicht mehr ausüben kannst — in der Regel ab einem Grad von 50 %.","Die Höhe der Rente und die Leistungsdauer (oft bis zum Renteneintritt) werden im Vertrag festgelegt. Manche Verträge enthalten eine Dynamik, die Beitrag und Leistung über die Jahre erhöht.","Die gesetzliche Erwerbsminderungsrente greift nur unter engeren Voraussetzungen und fällt meist deutlich niedriger aus. Das ist der Hintergrund, vor dem viele eine private Absicherung prüfen.","Diese Erklärung beschreibt nur, wie das Produkt funktioniert. Ob und in welcher Höhe eine Absicherung für dich sinnvoll ist, hängt von deiner persönlichen Situation ab."]'::jsonb, '["Disability insurance pays an agreed monthly pension if you can probably no longer work in your most recent occupation for health reasons on a lasting basis — usually from a degree of 50%.","The amount of the pension and the benefit period (often until retirement) are set in the contract. Some contracts include a dynamic increase that raises both premium and benefit over the years.","The statutory reduced-earning-capacity pension applies only under narrower conditions and is usually much lower. That is the background against which many people review private cover.","This explanation only describes how the product works. Whether and to what extent cover makes sense for you depends on your personal situation."]'::jsonb, 'berufsunfaehigkeit', 10, true),
  ('haftpflicht', 'Versicherung', 'Insurance', 'Was deckt eine Privathaftpflicht ab?', 'What does personal liability cover?', '["Die Privathaftpflichtversicherung übernimmt Schäden, die du als Privatperson anderen zufügst — etwa Personen-, Sach- oder daraus folgende Vermögensschäden.","Zentral ist die Deckungssumme: der Höchstbetrag, den der Versicherer pro Schadensfall zahlt. Übliche Größenordnungen liegen im einstelligen bis zweistelligen Millionenbereich.","Eine Selbstbeteiligung bedeutet, dass du einen festgelegten Teil jedes Schadens selbst trägst. Sie senkt tendenziell den Beitrag.","Mehrere Personen können über einen Vertrag versichert sein (Einzelperson, Paar, Familie). Das ist relevant, wenn du prüfst, ob mehrere Policen denselben Schutz doppelt abdecken."]'::jsonb, '["Personal liability insurance covers damage you cause to others as a private individual — for example personal injury, property damage or resulting financial loss.","The key figure is the coverage amount: the maximum the insurer pays per claim. Common levels range from single- to double-digit millions.","A deductible means you bear a fixed part of each claim yourself. It tends to lower the premium.","Several people can be insured under one contract (single, couple, family). This matters when you check whether several policies cover the same risk twice."]'::jsonb, 'privathaftpflicht', 20, true),
  ('deckungssumme', 'Versicherung', 'Insurance', 'Was bedeutet eine Deckungssumme?', 'What does a coverage amount mean?', '["Die Deckungssumme ist der maximale Betrag, den eine Versicherung für einen versicherten Schaden leistet. Liegt der tatsächliche Schaden darüber, trägst du die Differenz selbst.","Bei Haftpflichtversicherungen wird die Deckungssumme oft pauschal für Personen-, Sach- und Vermögensschäden angegeben — sie gilt dann gemeinsam für alle diese Schadenarten.","Eine höhere Deckungssumme erhöht den Schutz, wirkt sich aber meist nur moderat auf den Beitrag aus. Der Vergleich der Deckungssummen ist deshalb eine reine Faktenbetrachtung, keine Bewertung."]'::jsonb, '["The coverage amount is the maximum a policy pays for an insured claim. If the actual loss exceeds it, you bear the difference yourself.","For liability policies the coverage amount is often stated as a single figure for personal injury, property and financial loss — it then applies jointly to all of these.","A higher coverage amount increases protection but usually affects the premium only moderately. Comparing coverage amounts is therefore a purely factual look, not an assessment."]'::jsonb, null, 30, true),
  ('ter', 'Geldanlage', 'Investing', 'Was sind laufende Fondskosten (TER)?', 'What are ongoing fund costs (TER)?', '["Die TER (Total Expense Ratio, deutsch Gesamtkostenquote) gibt an, welcher Anteil deines angelegten Vermögens pro Jahr für die laufenden Kosten eines Fonds anfällt — unabhängig davon, ob der Fonds Gewinn oder Verlust macht.","Beispiel: Bei einer TER von 1,5 % p.a. und 10.000 € Anlagesumme fallen rechnerisch rund 150 € pro Jahr an laufenden Kosten an. Bei 0,2 % p.a. wären es etwa 20 €.","Breit streuende Index-ETFs liegen häufig im Bereich von 0,1 % bis 0,4 % p.a., aktiv gemanagte Fonds oft deutlich höher. Die TER ist nur einer von mehreren Kostenfaktoren.","Wir zeigen die TER deiner Positionen als nackte Zahl im Vergleich zum Marktdurchschnitt. Was du daraus machst, bleibt deine Entscheidung."]'::jsonb, '["The TER (Total Expense Ratio) shows what share of your invested capital is consumed each year by a fund''s running costs — regardless of whether the fund gains or loses.","Example: at a TER of 1.5% p.a. and 10,000 € invested, around 150 € of running costs arise per year. At 0.2% p.a. it would be about 20 €.","Broadly diversified index ETFs are often in the range of 0.1% to 0.4% p.a., while actively managed funds are frequently much higher. The TER is only one of several cost factors.","We show the TER of your positions as a plain number compared with the market average. What you make of it remains your decision."]'::jsonb, 'depot', 40, true),
  ('renteninformation', 'Vorsorge', 'Provision', 'Wie liest man eine Renteninformation?', 'How do you read a pension statement?', '["Die jährliche Renteninformation der Deutschen Rentenversicherung nennt unter anderem deine bisher erreichte Rente und eine Hochrechnung bis zum Rentenbeginn — jeweils als Brutto-Monatsbetrag.","Wichtig ist der Unterschied zwischen garantierten und prognostizierten Beträgen: Prognosen unterstellen Annahmen (etwa künftige Beiträge oder Überschüsse), die nicht garantiert sind.","Von der genannten Bruttorente gehen später noch Steuern und Beiträge zur Kranken- und Pflegeversicherung ab. Die Kaufkraft sinkt zusätzlich durch Inflation.","In der App summieren wir die prognostizierten Monatsrenten deiner erfassten Vorsorge-Verträge zu einer einfachen Momentaufnahme — ohne Hochrechnung und ohne Bewertung."]'::jsonb, '["The annual pension statement from the German pension insurance shows, among other things, the pension you have earned so far and a projection to retirement — each as a gross monthly amount.","The difference between guaranteed and projected amounts matters: projections assume things (such as future contributions or surpluses) that are not guaranteed.","Tax and contributions to health and care insurance are later deducted from the stated gross pension. Purchasing power also falls due to inflation.","In the app we add up the projected monthly pensions of your recorded provision contracts into a simple snapshot — without projection and without assessment."]'::jsonb, 'altersvorsorge', 50, true),
  ('duplicate', 'Grundlagen', 'Basics', 'Was bedeutet eine Dopplung?', 'What does a duplicate mean?', '["Von einer Dopplung sprechen wir, wenn in deinem Bestand mehrere Verträge derselben Art vorhanden sind — zum Beispiel zwei Privathaftpflichtpolicen.","Bei vielen Versicherungsarten leistet im Schadensfall ohnehin nur ein Vertrag; ein zweiter erhöht den Schutz dann nicht, verursacht aber weiterhin Beiträge.","Es gibt Ausnahmen — etwa bewusst kombinierte Zusatzbausteine. Deshalb ist die Dopplung ein Hinweis zum Prüfen, keine Aufforderung zum Kündigen.","Wir nennen dir nur die Tatsache und die zusammengerechneten Jahreskosten. Die Entscheidung triffst du."]'::jsonb, '["We speak of a duplicate when your portfolio contains several contracts of the same type — for example two personal liability policies.","For many types of insurance only one contract pays out in a claim anyway; a second one does not increase protection but still costs premiums.","There are exceptions — such as deliberately combined add-on modules. That is why a duplicate is a prompt to review, not a call to cancel.","We only state the fact and the combined annual cost. The decision is yours."]'::jsonb, null, 60, true),
  ('pflege', 'Vorsorge', 'Provision', 'Wie funktioniert die Pflegeabsicherung?', 'How does long-term care cover work?', '["Die gesetzliche Pflegeversicherung leistet je nach Pflegegrad einen festen Betrag — dieser deckt die tatsächlichen Pflegekosten in vielen Fällen nicht vollständig ab.","Private Zusatztarife schließen diese Lücke unterschiedlich: als Pflegetagegeld (fester Betrag je Tag), als Kostenerstattung oder als Pflegerente.","Wesentlich sind die Leistungshöhe je Pflegegrad, ob die Leistung mit der Zeit steigt und welche Wartezeiten gelten.","Diese Erklärung ordnet die Bausteine ein. Ob eine Zusatzabsicherung für dich passt, hängt von deiner Situation ab."]'::jsonb, '["Statutory care insurance pays a fixed amount depending on the care level — in many cases this does not fully cover the actual cost of care.","Private supplements close this gap in different ways: as a daily care allowance (a fixed amount per day), as cost reimbursement or as a care pension.","What matters is the benefit per care level, whether it rises over time and which waiting periods apply.","This explanation classifies the building blocks. Whether a supplement fits you depends on your situation."]'::jsonb, 'pflegeversicherung', 70, true),
  ('unfall', 'Versicherung', 'Insurance', 'Wofür ist eine Unfallversicherung gedacht?', 'What is accident insurance for?', '["Die private Unfallversicherung leistet bei bleibenden gesundheitlichen Schäden infolge eines Unfalls, üblicherweise als Einmalkapital.","Die Höhe richtet sich nach der Invaliditätssumme und der vereinbarten Progression, die bei schweren Schäden überproportional auszahlt.","Sie greift nur bei Unfällen — nicht bei Krankheit. Eine Berufsunfähigkeitsabsicherung deckt einen breiteren Bereich ab und wird oft getrennt betrachtet.","Hier geht es um die Funktionsweise. Die Beobachtungen in der App vergleichen nur Fakten, sie bewerten nicht."]'::jsonb, '["Private accident insurance pays out for lasting health damage following an accident, usually as a lump sum.","The amount depends on the disability sum and the agreed progression, which pays disproportionately more for severe damage.","It only applies to accidents — not to illness. Disability cover spans a broader range and is often considered separately.","This is about how it works. The observations in the app only compare facts; they do not judge."]'::jsonb, 'unfallversicherung', 80, true),
  ('hausrat', 'Versicherung', 'Insurance', 'Was versichert eine Hausratversicherung?', 'What does household contents insurance cover?', '["Die Hausratversicherung ersetzt bewegliche Gegenstände im Haushalt — etwa Möbel, Kleidung und Elektronik — bei Schäden durch Feuer, Leitungswasser, Sturm, Hagel oder Einbruchdiebstahl.","Die Versicherungssumme sollte zum Wert des Hausrats passen. Ist sie zu niedrig (Unterversicherung), kann der Versicherer Leistungen anteilig kürzen.","Elementarschäden wie Überschwemmung sind nicht automatisch enthalten, sondern oft ein gesonderter Baustein.","Die Erklärung beschreibt den Umfang. Ob und in welcher Höhe Schutz sinnvoll ist, entscheidest du."]'::jsonb, '["Household contents insurance replaces movable items in the home — such as furniture, clothing and electronics — for damage from fire, water, storm, hail or burglary.","The sum insured should match the value of the contents. If it is too low (underinsurance), the insurer may reduce benefits proportionally.","Natural-hazard damage such as flooding is not automatically included and is often a separate module.","The explanation describes the scope. Whether and how much cover makes sense is your decision."]'::jsonb, 'hausratversicherung', 90, true),
  ('wohngebaeude', 'Versicherung', 'Insurance', 'Was deckt eine Wohngebäudeversicherung?', 'What does building insurance cover?', '["Die Wohngebäudeversicherung schützt das Gebäude selbst — Mauerwerk, Dach und fest Verbautes — vor Schäden durch Feuer, Leitungswasser, Sturm und Hagel.","Für Eigentümer ist sie zentral, da ein größerer Gebäudeschaden hohe Wiederaufbaukosten verursacht.","Ob Elementarschäden wie Überschwemmung oder Erdbeben eingeschlossen sind, hängt vom gewählten Umfang ab.","Diese Information erklärt die Funktionsweise und ersetzt keine individuelle Beratung."]'::jsonb, '["Building insurance protects the building itself — structure, roof and fixtures — against fire, water, storm and hail damage.","It is central for owners, since major building damage causes high rebuild costs.","Whether natural hazards such as flooding or earthquakes are included depends on the chosen scope.","This information explains how it works and does not replace individual advice."]'::jsonb, 'wohngebaeudeversicherung', 100, true),
  ('rechtsschutz', 'Versicherung', 'Insurance', 'Wofür ist eine Rechtsschutzversicherung da?', 'What is legal expenses insurance for?', '["Die Rechtsschutzversicherung übernimmt Kosten rechtlicher Auseinandersetzungen — Anwalt, Gericht und Gutachten — in den vereinbarten Lebensbereichen.","Üblich sind Bausteine für Privat-, Berufs-, Verkehrs- und Wohnrecht, die einzeln oder kombiniert abgeschlossen werden.","Häufig gibt es eine Wartezeit zu Beginn und eine Selbstbeteiligung je Fall. Nicht jeder Streit ist abgedeckt.","Wir erklären nur den Umfang. Ob der Schutz zu dir passt, hängt von deiner Lebenssituation ab."]'::jsonb, '["Legal expenses insurance covers the cost of legal disputes — lawyer, court and expert opinions — in the agreed areas of life.","Common modules cover private, employment, traffic and housing law, taken individually or combined.","There is often a waiting period at the start and a deductible per case. Not every dispute is covered.","We only explain the scope. Whether the cover fits you depends on your circumstances."]'::jsonb, 'rechtsschutzversicherung', 110, true),
  ('liquiditaet', 'Grundlagen', 'Basics', 'Warum eine Liquiditätsreserve?', 'Why a liquidity reserve?', '["Eine Liquiditätsreserve ist schnell verfügbares Geld für unerwartete Ausgaben wie eine kaputte Waschmaschine oder eine Autoreparatur.","In der Logik einer anerkannten Bedarfssystematik steht sie am Anfang: erst eine Reserve, dann langfristiges Sparen und Investieren.","Als grobe Orientierung dienen einige Monatsausgaben — der passende Betrag hängt von deiner Lebenssituation ab.","Wichtig ist, dass das Geld jederzeit verfügbar ist, etwa auf einem Tagesgeldkonto."]'::jsonb, '["A liquidity reserve is readily available money for unexpected expenses such as a broken washing machine or a car repair.","In the logic of a recognised needs hierarchy it comes first: a reserve before any long-term saving and investing.","A few months of expenses serve as rough orientation — the right amount depends on your circumstances.","What matters is that the money is available at any time, for example in an instant-access savings account."]'::jsonb, 'liquiditaetsreserve', 120, true)
